import React, { useState } from 'react';
import Layout from './components/Layout';
import FundView from './components/FundView';
import StockDashboard from './components/StockDashboard';
import StockSearch from './components/StockSearch';
import TrackingDashboard from './components/TrackingDashboard/TrackingDashboard';
import ConfigurationView from './components/Configuration/ConfigurationView';
import { FundSnapshot, FundSearchResult } from './types';

function App() {
  const [activeTab, setActiveTab] = useState<string>('DASHBOARD');
  const [funds, setFunds] = useState<FundSnapshot[]>();
  const [selectedStock, setSelectedStock] = useState<{symbol: string, name: string} | null>(null);

  // Update state to hold full object or null
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(null);

  // Handle Navigation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab !== 'STOCK_DETAIL') {
      setSelectedStock(null);
    }
  };

  const handleFundDataAdded = (newData: FundSnapshot) => {
    setFunds(prev => {
       // Avoid duplicates based on ID
       if (prev && prev.find(f => f.id === newData.id)) return prev;
       return prev ? [...prev, newData] : [newData];
    });
  };

  const handleSelectStock = (symbol: string, name: string) => {
    setSelectedStock({ symbol, name });
    setActiveTab('STOCK_DETAIL');
  };

  const handleSelectFundFromDashboard = (fund: FundSearchResult) => {
    console.log("Navigating to fund:", fund.name);
    setSelectedFund(fund);
    setActiveTab('FUND_DETAIL');
  };

  const renderContent = () => {
    if (activeTab === 'STOCK_DETAIL' && selectedStock) {
      return (
        <StockDashboard 
          symbol={selectedStock.symbol} 
          stockName={selectedStock.name}
          onBack={() => handleTabChange('STOCK_SEARCH')}
          onSelectFund={handleSelectFundFromDashboard}
        />
      );
    }

    switch (activeTab) {
      case 'DASHBOARD':
        return <TrackingDashboard />;
      case 'FUND_DETAIL':
        return (
          <FundView 
            funds={funds || []} 
            onFundDataAdded={handleFundDataAdded} 
            onSelectStock={handleSelectStock}
            initialSelectedFund={selectedFund}
          />
        );
      case 'STOCK_SEARCH':
        return (
          <StockSearch onSelectStock={handleSelectStock} />
        );
      case 'CONFIGURATION':
        return <ConfigurationView />;
      default:
        return <TrackingDashboard />;
    }
  };

  return (
    <Layout activeTab={activeTab === 'STOCK_DETAIL' ? 'STOCK_SEARCH' : activeTab} onTabChange={handleTabChange}>
      {renderContent()}
    </Layout>
  );
}

export default App;

import { EntityType } from '../types/trackingTypes';

export interface TrackedItem {
  id: string; // Symbol for Stocks, PK for MFs
  name: string;
  symbol?: string; // Optional for MFs
  type: EntityType;
  url?: string; // For navigation (e.g. Fund URL)
}

const STORAGE_KEY = 'fundflow_tracked_items';

export const getTrackedItems = (): TrackedItem[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    console.error("Error parsing tracked items", e);
    return [];
  }
};

export const addTrackedItem = (item: TrackedItem) => {
  const items = getTrackedItems();
  // Prevent duplicates
  if (!items.find(i => i.id === item.id && i.type === item.type)) {
    const newItems = [...items, item];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
  }
};

export const removeTrackedItem = (id: string, type: EntityType) => {
  const items = getTrackedItems();
  const newItems = items.filter(i => !(i.id === id && i.type === type));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
};

export const isTracked = (id: string, type: EntityType): boolean => {
  const items = getTrackedItems();
  return !!items.find(i => i.id === id && i.type === type);
};

