import React, { useState, useMemo, useEffect } from 'react';
import { Search, SlidersHorizontal, Loader2, PlusCircle } from 'lucide-react';
import DashboardSidebar from './DashboardSidebar';
import InsightCard from './InsightCard';
import { getTrackedItems, TrackedItem } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { Insight } from '../../types/trackingTypes';

const TrackingDashboard: React.FC = () => {
  const [selectedType, setSelectedType] = useState<'ALL' | 'STOCK' | 'MF'>('ALL');
  const [selectedEntityId, setSelectedEntityId] = useState<string | 'ALL'>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  // Real Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Load Tracked Items
  useEffect(() => {
    const loadedEntities = getTrackedItems();
    setEntities(loadedEntities);

    // Generate Insights if we have entities
    if (loadedEntities.length > 0) {
      setLoadingInsights(true);
      fetchMarketInsights(loadedEntities)
        .then(data => {
            setInsights(data);
            setLoadingInsights(false);
        })
        .catch(err => {
            console.error(err);
            setLoadingInsights(false);
        });
    } else {
        setInsights([]);
    }
  }, []); // Run once on mount

  // Filter Logic
  const filteredInsights = useMemo(() => {
    let filtered = insights;

    // Filter by specific Entity ID
    if (selectedEntityId !== 'ALL') {
        filtered = filtered.filter(i => i.entityId === selectedEntityId);
    } 
    // Or Filter by Type if no specific entity selected
    else if (selectedType !== 'ALL') {
        const validIds = entities.filter(e => e.type === selectedType).map(e => e.id);
        filtered = filtered.filter(i => validIds.includes(i.entityId));
    }

    // Filter by Search Query
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }

    // Enrich with Entity Data
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  }, [insights, entities, selectedEntityId, selectedType, searchQuery]);

  const currentEntityName = selectedEntityId === 'ALL' 
    ? 'All Tracked Assets' 
    : entities.find(e => e.id === selectedEntityId)?.name;

  return (
    <div className="flex flex-col md:flex-row gap-6 animate-fade-in">
      {/* Sidebar Navigation */}
      <DashboardSidebar 
        entities={entities}
        selectedEntityId={selectedEntityId}
        selectedType={selectedType}
        onSelectEntity={setSelectedEntityId}
        onSelectType={setSelectedType}
      />

      {/* Main Content Area */}
      <div className="flex-1 space-y-6">

        {/* Header & Search */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
           <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-2xl font-bold text-gray-900">{currentEntityName}</h2>
                <p className="text-gray-500 text-sm">
                  {selectedEntityId === 'ALL' 
                    ? `Showing latest updates for ${selectedType === 'ALL' ? 'all portfolio items' : selectedType === 'STOCK' ? 'stocks' : 'mutual funds'}`
                    : `Tracking ID: ${selectedEntityId} • ${filteredInsights.length} Updates`
                  }
                </p>
              </div>

              <div className="relative w-full md:w-80">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-400" />
                </div>
                <input 
                  type="text" 
                  className="bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-3 transition-shadow" 
                  placeholder="Search insights, news..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
           </div>
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-3 gap-4">
            <div className="bg-gradient-to-br from-indigo-500 to-indigo-600 rounded-xl p-4 text-white shadow-sm">
                <div className="text-xs font-medium opacity-80 mb-1">Total Insights</div>
                <div className="text-2xl font-bold">{loadingInsights ? '-' : filteredInsights.length}</div>
            </div>
            <div className="bg-white rounded-xl p-4 border border-gray-100 shadow-sm">
                <div className="text-xs font-medium text-gray-500 mb-1">Positive Sentiment</div>
                <div className="text-2xl font-bold text-green-600">
                   {loadingInsights ? '-' : (filteredInsights.length > 0 ? Math.round((filteredInsights.filter(i => i.sentiment === 'POSITIVE').length / filteredInsights.length) * 100) : 0)}%
                </div>
            </div>
            <div className="bg-white rounded-xl p-4 border border-gray-100 shadow-sm">
                <div className="text-xs font-medium text-gray-500 mb-1">Active Assets</div>
                <div className="text-2xl font-bold text-gray-800">{entities.length}</div>
            </div>
        </div>

        {/* Feed */}
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-sm font-semibold text-gray-700 pb-2 border-b border-gray-100">
             <SlidersHorizontal size={16} />
             <span>Insight Stream</span>
             {loadingInsights && <Loader2 size={16} className="animate-spin text-indigo-500 ml-2" />}
          </div>

          {loadingInsights && filteredInsights.length === 0 ? (
             <div className="p-12 flex flex-col items-center justify-center space-y-3">
                <Loader2 size={32} className="animate-spin text-indigo-600" />
                <p className="text-gray-500 text-sm">Analyzing your watchlist with Gemini...</p>
             </div>
          ) : filteredInsights.length > 0 ? (
            <div className="grid grid-cols-1 gap-4">
              {filteredInsights.map(insight => (
                <InsightCard key={insight.id} insight={insight} />
              ))}
            </div>
          ) : (
            <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
               {entities.length === 0 ? (
                  <>
                     <p className="text-gray-500 font-medium">Your watchlist is empty.</p>
                     <p className="text-gray-400 text-sm mt-1">Add stocks or mutual funds from the Search pages to see insights here.</p>
                  </>
               ) : (
                  <>
                     <p className="text-gray-500">No insights found matching your criteria.</p>
                     <button 
                        onClick={() => { setSearchQuery(''); setSelectedType('ALL'); setSelectedEntityId('ALL'); }}
                        className="mt-2 text-indigo-600 font-medium text-sm hover:underline"
                     >
                        Clear Filters
                     </button>
                  </>
               )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

