import React, { useState, useMemo, useEffect } from 'react';
import { Search, Loader2, RefreshCw, Database, Sparkles } from 'lucide-react';
import DashboardSidebar from './DashboardSidebar';
import InsightCard from './InsightCard';
import DataStream from './DataStream';
import { getTrackedItems, TrackedItem } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { Insight } from '../../types/trackingTypes';

const TrackingDashboard: React.FC = () => {
  const [selectedType, setSelectedType] = useState<'ALL' | 'STOCK' | 'MF'>('ALL');
  const [selectedEntityId, setSelectedEntityId] = useState<string | 'ALL'>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  // Tabs State
  const [activeStreamTab, setActiveStreamTab] = useState<'DATA' | 'AI'>('DATA');

  // Real Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Track if we have fetched insights for the current view context
  const [insightsFetched, setInsightsFetched] = useState(false);

  // Load Tracked Items on mount
  useEffect(() => {
    const loadedEntities = getTrackedItems();
    setEntities(loadedEntities);
  }, []);

  // Filter Entities based on selection
  const visibleEntities = useMemo(() => {
     if (selectedEntityId !== 'ALL') {
         return entities.filter(e => e.id === selectedEntityId);
     }
     if (selectedType !== 'ALL') {
         return entities.filter(e => e.type === selectedType);
     }
     return entities;
  }, [entities, selectedEntityId, selectedType]);

  const fetchInsights = async () => {
     if (visibleEntities.length === 0) return;

     setLoadingInsights(true);
     try {
         const data = await fetchMarketInsights(visibleEntities);
         setInsights(data);
         setInsightsFetched(true);
     } catch (err) {
         console.error(err);
     } finally {
         setLoadingInsights(false);
     }
  };

  // Reset insights fetched state when selection changes, but don't auto-fetch unless in AI tab
  useEffect(() => {
      setInsightsFetched(false);
      setInsights([]);

      // If user switches context while in AI tab, auto-refresh insights
      if (activeStreamTab === 'AI') {
          // Debounce slightly to avoid rapid clicks firing multiple requests
          const timer = setTimeout(() => {
              // We need to fetch for the *new* visibleEntities. 
              // Since visibleEntities is a dependency, this effect runs when it changes.
              // However, we can't call fetchInsights() directly here easily because it relies on the state which is updating.
              // Let's rely on a separate effect for fetching.
          }, 100);
          return () => clearTimeout(timer);
      }
  }, [selectedEntityId, selectedType]);

  // Effect to handle AI Tab activation or Context Switch while Active
  useEffect(() => {
      if (activeStreamTab === 'AI' && !insightsFetched && !loadingInsights && visibleEntities.length > 0) {
          fetchInsights();
      }
  }, [activeStreamTab, visibleEntities, insightsFetched]);


  // Filter Insights for Display
  const filteredInsights = useMemo(() => {
    let filtered = insights;

    // Filter by Search Query
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }

    // Enrich with Entity Data
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  }, [insights, entities, searchQuery]);

  const currentEntityName = selectedEntityId === 'ALL' 
    ? 'All Tracked Assets' 
    : entities.find(e => e.id === selectedEntityId)?.name;

  return (
    <div className="flex flex-col md:flex-row gap-6 animate-fade-in">
      {/* Sidebar Navigation */}
      <DashboardSidebar 
        entities={entities}
        selectedEntityId={selectedEntityId}
        selectedType={selectedType}
        onSelectEntity={setSelectedEntityId}
        onSelectType={setSelectedType}
      />

      {/* Main Content Area */}
      <div className="flex-1 space-y-6">

        {/* Header & Search */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
           <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-2xl font-bold text-gray-900">{currentEntityName}</h2>
                <p className="text-gray-500 text-sm">
                  {selectedEntityId === 'ALL' 
                    ? `Tracking ${visibleEntities.length} item${visibleEntities.length !== 1 ? 's' : ''} in portfolio`
                    : `Tracking ID: ${selectedEntityId}`
                  }
                </p>
              </div>

              <div className="relative w-full md:w-80">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-400" />
                </div>
                <input 
                  type="text" 
                  className="bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-3 transition-shadow" 
                  placeholder="Search stream..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
           </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex items-center gap-4 border-b border-gray-200">
             <button
                onClick={() => setActiveStreamTab('DATA')}
                className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                    activeStreamTab === 'DATA' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Database size={16} />
                Data Stream
             </button>
             <button
                onClick={() => setActiveStreamTab('AI')}
                className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                    activeStreamTab === 'AI' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Sparkles size={16} />
                AI Stream
             </button>
        </div>

        {/* Stream Content */}
        <div className="min-h-[400px]">
           {activeStreamTab === 'DATA' ? (
              <DataStream entities={visibleEntities} />
           ) : (
              <div className="space-y-4">
                 <div className="flex items-center justify-between pb-2">
                    <p className="text-xs text-gray-500">
                        {loadingInsights 
                          ? 'Analyzing market data...' 
                          : `${filteredInsights.length} insights generated via Gemini`
                        }
                    </p>
                    <button 
                        onClick={fetchInsights} 
                        disabled={loadingInsights}
                        className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-gray-100 rounded-full transition-colors"
                        title="Refresh AI Insights"
                    >
                        <RefreshCw size={16} className={loadingInsights ? "animate-spin text-indigo-600" : ""} />
                    </button>
                 </div>

                 {loadingInsights && filteredInsights.length === 0 ? (
                    <div className="p-12 flex flex-col items-center justify-center space-y-3 bg-white rounded-xl border border-gray-100">
                        <Loader2 size={32} className="animate-spin text-indigo-600" />
                        <p className="text-gray-500 text-sm">Gathering intelligent insights...</p>
                    </div>
                 ) : filteredInsights.length > 0 ? (
                    <div className="grid grid-cols-1 gap-4">
                        {filteredInsights.map(insight => (
                            <InsightCard key={insight.id} insight={insight} />
                        ))}
                    </div>
                 ) : (
                    <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
                        <p className="text-gray-500">No specific insights available at this moment.</p>
                        <button 
                            onClick={fetchInsights}
                            className="mt-2 text-indigo-600 font-medium text-sm hover:underline"
                        >
                            Try Refreshing
                        </button>
                    </div>
                 )}
              </div>
           )}
        </div>
      </div>
    </div>
  );
};

