        if (data && Array.isArray(data.tableData)) {
            rows = data.tableData;
        } else if (Array.isArray(data)) {
            rows = data;
        } else if (data && data.data && Array.isArray(data.data)) {
             rows = data.data;
        }

        // Sanitize rows to ensure no nested objects leak into UI strings
