        sectorDistribution = sectorRaw.map((item: any) => ({
            name: item.name || "Unknown",
            value: Number(item.value) || 0
        }));
    }

    return {
        holdings,
        meta,
        sectorDistribution
    };

  } catch (error) {
    console.error("Error fetching fund portfolio data:", error);
    return null;
  }
};

